class LmdbStarJoinScanSupportTest {

	@Test
	void starMultiPredicateScanRecognizesSameSubjectDistinctConstantPredicates() {
		TupleExpr join = new Join(constantPredicatePattern("s", "urn:p1", "o1"),
				constantPredicatePattern("s", "urn:p2", "o2"));

		Optional<LmdbStarJoinScanSupport.Plan> plan = LmdbStarJoinScanSupport.plan(join);

		assertTrue(plan.isPresent());
		assertEquals("s", plan.get().subjectName());
		assertEquals(2, plan.get().patterns().size());
		assertEquals(Set.of("urn:p1", "urn:p2"), plan.get().predicateValues());
	}

	@Test
	void starMultiPredicateScanRejectsDifferentSubjects() {
		TupleExpr join = new Join(constantPredicatePattern("s1", "urn:p1", "o1"),
				constantPredicatePattern("s2", "urn:p2", "o2"));

		assertTrue(LmdbStarJoinScanSupport.plan(join).isEmpty());
	}

	@Test
	void starMultiPredicateScanRejectsDuplicatePredicates() {
		TupleExpr join = new Join(constantPredicatePattern("s", "urn:p1", "o1"),
				constantPredicatePattern("s", "urn:p1", "o2"));

		assertTrue(LmdbStarJoinScanSupport.plan(join).isEmpty());
	}

	@Test
	void starMultiPredicateScanRejectsVariablePredicates() {
		TupleExpr join = new Join(new StatementPattern(new Var("s"), new Var("p"), new Var("o")),
				constantPredicatePattern("s", "urn:p1", "o2"));

		assertTrue(LmdbStarJoinScanSupport.plan(join).isEmpty());
	}

	@Test
	void starMultiPredicateRuleDeliversSubjectDistinctEvidence() {
		TupleExpr join = new Join(constantPredicatePattern("s", "urn:p1", "o1"),
				constantPredicatePattern("s", "urn:p2", "o2"));
		StarStatistics statistics = new StarStatistics();
		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		int groupId = memo.intern(join);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();

		RuleApplication application = new LmdbStarMultiPredicateScanRule(statistics)
				.apply(expression, OptimizationGoal.root(),
						new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null))
				.getFirst();

		VariableEstimate subject = application.deliveredProperties().bindingProfile().variables().get("s");
		assertNotNull(subject, "The star alternative must expose its subject evidence to parent operators");
		assertEquals(12.0d, subject.distinctRows(), 0.0d);
		assertFalse(application.opaque(), "A composite star must retain independently optimizable memo children");
		assertEquals(CostVector.ZERO, application.localCost(),
				"The rule must not price the complete star subtree before child winners are selected");

		MemoExpr physical = memo
				.addPhysicalAlternative(groupId, application.alternative(), application.deliveredProperties(),
						application.inputRequirements(), application.metadata(), application.kind(),
						application.localCost(), application.proofs(), application.estimate(), application.opaque())
				.orElseThrow();
		assertEquals(expression.inputGroupIds(), physical.inputGroupIds(),
				"The physical star must keep both factor groups visible to memo search and recosting");
	}

	@Test
	void starMultiPredicateRuleDeclinesObjectBoundStarWithUnboundSubject() {
		TupleExpr join = new Join(constantPredicatePattern("copy", "urn:locatedAt", "branch"),
				new StatementPattern(new Var("copy"),
						new Var("typePredicate", SimpleValueFactory.getInstance().createIRI("urn:type")),
						new Var("copyType", SimpleValueFactory.getInstance().createIRI("urn:Copy"))));
		StarStatistics statistics = new StarStatistics();
		CascadesCostModel costModel = CascadesCostModel.from(statistics);
		Memo memo = new Memo(costModel);
		int groupId = memo.intern(join);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();
		OptimizationGoal goal = OptimizationGoal.root()
				.withRequiredProperties(PhysicalProperties.builder().boundVars(Set.of("branch")).build());

		List<RuleApplication> applications = new LmdbStarMultiPredicateScanRule(statistics)
				.apply(expression, goal, new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null));

		assertTrue(applications.isEmpty(),
				"An object-bound star with an unbound shared subject needs ordinary join ordering; a subject-prefix "
						+ "batch scan cannot consume the external object key as a whole-star access path");
	}

	private static StatementPattern constantPredicatePattern(String subject, String predicateIri, String object) {
		return new StatementPattern(new Var(subject),
				new Var("p", SimpleValueFactory.getInstance().createIRI(predicateIri)), new Var(object));
	}

	private static final class StarStatistics extends EvaluationStatistics implements RdfStatisticsProvider {
		@Override
		public Optional<StatisticsEstimate> starMultiPredicateScan(List<StatementPattern> starPatterns,
				Set<String> boundVars) {
			BagEstimate bag = BagEstimate.heuristic(48.0d, "omni-subject-star")
					.withVariable("s", VariableEstimate.bound(48.0d, 12.0d));
			return Optional.of(new StatisticsEstimate(48.0d,
					QErrorInterval.heuristic(48.0d, 1.5d, "omni-subject-star"), 48.0d,
					"omni-subject-star", Map.of(), bag));
		}
	}
}
